import{_ as t,o as a,c as s,a0 as i}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Visual Regression Testing","description":"","frontmatter":{},"headers":[],"relativePath":"guide/visual-regression.md","filePath":"guide/visual-regression.md","lastUpdated":1784187737000}'),n={name:"guide/visual-regression.md"};function o(r,e,l,d,h,c){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="visual-regression-testing" tabindex="-1">Visual Regression Testing <a class="header-anchor" href="#visual-regression-testing" aria-label="Permalink to &quot;Visual Regression Testing&quot;">​</a></h1><p>This page is the baseline-review process that <a href="/enterprise-readiness">Enterprise Readiness → Phase 5</a> identified as the actual cost of visual regression testing — the tooling (<code>toHaveScreenshot()</code>) is a few lines; deciding who approves a changed screenshot and when a diff is expected versus a regression is the part that actually needs a process, not just a config file.</p><h2 id="what-s-covered-today" tabindex="-1">What&#39;s covered today <a class="header-anchor" href="#what-s-covered-today" aria-label="Permalink to &quot;What&#39;s covered today&quot;">​</a></h2><p><code>tests-e2e/visual.spec.ts</code> — four scenarios, all built on states achievable with the library&#39;s <em>current</em> feature set:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Snapshot</th></tr></thead><tbody><tr><td>Unstyled <code>srcdoc</code>, no injection</td><td><code>unstyled-preview.png</code></td></tr><tr><td>Dark-themed CSS injection</td><td><code>themed-preview-dark.png</code></td></tr><tr><td>Light-themed CSS injection</td><td><code>themed-preview-light.png</code></td></tr><tr><td>JS-mutated content</td><td><code>js-mutated-preview.png</code></td></tr></tbody></table><p><strong>Not covered, on purpose:</strong> an error/loading-slot state and an auto-height state. Neither exists in the library yet — they&#39;re proposals in <a href="/feature-recommendations"><code>FEATURE_RECOMMENDATIONS.md</code></a> (#3 and #4). Add scenarios for them here once they land; committing placeholder screenshots for features that don&#39;t exist would just be baselines to immediately break.</p><h2 id="why-one-pinned-browser-not-three" tabindex="-1">Why one pinned browser, not three <a class="header-anchor" href="#why-one-pinned-browser-not-three" aria-label="Permalink to &quot;Why one pinned browser, not three&quot;">​</a></h2><p>Visual tests run only under the dedicated <code>visual</code> Playwright project (see <code>playwright.config.ts</code>), pinned to Chromium at a fixed 1000×700 viewport. <code>chromium</code>, <code>firefox</code>, and <code>webkit</code> explicitly ignore <code>visual.spec.ts</code>. Screenshot comparison is sensitive to font rendering, sub-pixel anti-aliasing, and scrollbar rendering — real differences between browser engines (and even between OSes running the same engine) that have nothing to do with whether <em>this library</em> introduced a regression. Running the same assertion three ways would triple the baseline-maintenance cost for no corresponding increase in signal; cross-engine behavior is already what Phase 4&#39;s functional E2E suite is for.</p><h2 id="generating-and-updating-baselines" tabindex="-1">Generating and updating baselines <a class="header-anchor" href="#generating-and-updating-baselines" aria-label="Permalink to &quot;Generating and updating baselines&quot;">​</a></h2><p>No baseline images are committed by default — the first run for a new or changed scenario always fails with &quot;no baseline found,&quot; which is expected, not a bug.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Generate/update every visual baseline</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests-e2e/visual.spec.ts</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=visual</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --update-snapshots</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Generate/update a single scenario</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests-e2e/visual.spec.ts</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=visual</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --update-snapshots</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;dark-themed&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Commit the resulting <code>tests-e2e/visual.spec.ts-snapshots/</code> directory alongside your change. Snapshot filenames encode the project and platform (e.g. <code>themed-preview-dark-visual-linux.png</code>) — CI (Linux runners) and most developer machines (macOS/Windows) will produce differently-named baselines. <strong>Only the CI- generated (Linux) baseline is authoritative</strong> for what actually gates PRs; a locally regenerated baseline on macOS is useful for local iteration but isn&#39;t what <code>.github/workflows/e2e.yml</code> compares against.</p><h2 id="the-review-process" tabindex="-1">The review process <a class="header-anchor" href="#the-review-process" aria-label="Permalink to &quot;The review process&quot;">​</a></h2><p>This is the part that&#39;s a decision, not a tool setting:</p><ol><li><strong>A visual diff on an otherwise-passing PR is a stop sign, not noise.</strong> Playwright fails the test and attaches a diff image (red/green highlight) to the HTML report (<code>playwright-report/</code>, uploaded as a CI artifact — see <code>.github/workflows/e2e.yml</code>). Open it before doing anything else.</li><li><strong>Ask &quot;did I mean to change this?&quot;</strong> before regenerating anything. <ul><li>If the PR touches CSS defaults, the component&#39;s own <code>&lt;style&gt;</code> block, or the harness/theming used in the test itself → a diff is expected. Regenerate, visually re-check the new PNG yourself, and call it out explicitly in the PR description with a before/after (or just the new image).</li><li>If the PR is unrelated to styling (e.g. a composable refactor, a new prop unrelated to appearance) → an unexpected diff is a real signal. Investigate before touching snapshots — don&#39;t regenerate to make CI green.</li></ul></li><li><strong>A snapshot update needs the same review as a code change.</strong> <code>git diff</code> doesn&#39;t show PNG content usefully, so the PR description doing the explaining (point 2) matters more here than for a normal code diff — a reviewer approving a binary file they can&#39;t diff in the terminal needs the context stated, not implied.</li><li><strong>CODEOWNERS applies.</strong> <code>tests-e2e/**</code> is covered by the same <code>.github/CODEOWNERS</code> entry as the rest of the test suite — whoever owns that path is the approver for a snapshot change, same as any other file under it. (See <code>ENTERPRISE_READINESS.md</code> Phase 1 for the outstanding placeholder-handle caveat that also applies to this line.)</li><li><strong>Flaky, not failing?</strong> A genuinely flaky visual test (same code, intermittent diff) is itself a bug — usually an unfrozen animation, a font not yet loaded, or a timing race before the screenshot is taken. Fix the test (see &quot;Reducing flakiness&quot; below) rather than raising <code>maxDiffPixelRatio</code> to paper over it; a tolerance loose enough to hide flakiness is also loose enough to hide a real regression.</li></ol><h2 id="reducing-flakiness" tabindex="-1">Reducing flakiness <a class="header-anchor" href="#reducing-flakiness" aria-label="Permalink to &quot;Reducing flakiness&quot;">​</a></h2><p>Already configured, so new scenarios inherit these for free:</p><ul><li><code>expect.toHaveScreenshot.animations: &#39;disabled&#39;</code> (global, in <code>playwright.config.ts</code>) freezes CSS animations/transitions and caret blinking before capture.</li><li>A fixed <code>viewport: { width: 1000, height: 700 }</code> on the <code>visual</code> project, so layout doesn&#39;t shift with whatever the default viewport happens to be.</li><li><code>maxDiffPixelRatio: 0.02</code> per assertion — a small tolerance for genuine sub-pixel rendering noise, not a substitute for the flakiness triage above.</li></ul><p>If a new scenario is still flaky after that, the usual next culprits are: content that loads asynchronously after the <code>load</code> event (wait for it explicitly before the screenshot call, the way each existing test waits on <code>injected-count</code>/<code>last-injected- count</code> first), or a web font that hasn&#39;t finished loading (wait on <code>document.fonts.ready</code> inside the harness, or avoid custom fonts in visual fixtures entirely — the existing scenarios deliberately use <code>system-ui</code> for this reason).</p><h2 id="ci-behavior" tabindex="-1">CI behavior <a class="header-anchor" href="#ci-behavior" aria-label="Permalink to &quot;CI behavior&quot;">​</a></h2><p><code>.github/workflows/e2e.yml</code> runs all Playwright projects, including <code>visual</code>, on every push/PR — a visual regression fails the same build as a functional one. This is a deliberate choice: a silent, un-gated visual test would just be a report nobody reads. The tradeoff is that a legitimate visual change now requires the PR author to update snapshots <em>before</em> merging (see above) — slower, but the point of gating on it at all.</p>`,21)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
